INSERT INTO articles (title, slug, summary, content, threat_level, category, cves, affected_products, threat_actors, industries, attack_vector, source, source_url, published_at, updated_at, discovered_at, exploited_at, patched_at, verified, verified_by, tags, region) VALUES
('Lazarus Group Linked to $1.5B Bybit Cryptocurrency Heist', 'lazarus-bybit-crypto-heist-1-5b', 'FBI attributes the $1.5 billion Bybit cryptocurrency exchange hack to North Korea Lazarus Group. Largest crypto theft in history.', 'FBI confirmed Lazarus Group stole approximately $1.5 billion in crypto assets from Bybit through a sophisticated supply chain compromise of the Safe{Wallet} multisig infrastructure. Attackers compromised a developer machine to inject malicious code into the transaction signing process. Funds being laundered through chain-hopping and mixing services.', 'critical', 'data-breach', '{}', '{"Bybit Exchange","Safe Wallet","Ethereum","Cryptocurrency Infrastructure"}', '{"Lazarus Group"}', '{"finance","technology"}', 'Supply Chain / Developer Machine Compromise', 'FBI / Chainalysis', 'https://www.fbi.gov', '2026-03-19T14:00:00Z', '2026-03-20T09:00:00Z', '2026-02-21T00:00:00Z', '2026-02-21T00:00:00Z', NULL, true, '{"FBI","Chainalysis","TRM Labs"}', '{"cryptocurrency","north-korea","supply-chain","defi","lazarus"}', 'Global'),

('Black Basta Ransomware Pivots to Microsoft Teams Social Engineering', 'black-basta-teams-social-engineering', 'Black Basta affiliates using Microsoft Teams messages and Quick Assist for initial access, bypassing email security controls entirely.', 'Black Basta affiliates are impersonating IT help desk staff via Microsoft Teams, contacting employees about fake security issues and requesting Quick Assist remote sessions. Once connected, they deploy Cobalt Strike and ransomware payloads. Technique bypasses email-based security controls completely. Over 50 organizations targeted in March.', 'high', 'ransomware', '{}', '{"Microsoft Teams","Quick Assist","Windows 10/11","Cobalt Strike"}', '{"Black Basta"}', '{"manufacturing","finance","healthcare","technology","retail"}', 'Social Engineering / Microsoft Teams / Quick Assist', 'Microsoft Threat Intelligence', 'https://www.microsoft.com/security/blog', '2026-03-18T11:00:00Z', '2026-03-19T08:00:00Z', '2026-03-10T00:00:00Z', '2026-03-10T00:00:00Z', NULL, true, '{"Microsoft","CISA"}', '{"ransomware","social-engineering","teams","black-basta"}', 'Global'),

('Critical VMware ESXi Vulnerability Allows Guest-to-Host Escape', 'vmware-esxi-guest-host-escape', 'A critical use-after-free vulnerability in VMware ESXi allows virtual machine escape. Active exploitation by ransomware groups confirmed.', 'CVE-2026-22224 is a use-after-free in VMware ESXi USB controller allowing guest-to-host escape. Ransomware operators are using it to compromise entire virtualization estates from a single compromised VM. Broadcom has released patches for ESXi 7.0, 8.0, and vCenter Server. Mass scanning detected.', 'critical', 'vulnerability', '{"CVE-2026-22224","CVE-2026-22225"}', '{"VMware ESXi 7.0","VMware ESXi 8.0","vCenter Server","VMware Workstation"}', '{}', '{"technology","finance","healthcare","government"}', 'VM Escape / USB Controller Exploitation', 'Broadcom / Microsoft Threat Intelligence', 'https://support.broadcom.com', '2026-03-17T09:00:00Z', '2026-03-18T15:00:00Z', '2026-03-05T00:00:00Z', '2026-03-10T00:00:00Z', '2026-03-17T00:00:00Z', true, '{"Broadcom","CISA","Microsoft"}', '{"vmware","esxi","vm-escape","ransomware","virtualization"}', 'Global'),

('Sandworm Deploys New Wiper Malware Against Ukrainian Energy Grid', 'sandworm-wiper-ukraine-energy-grid', 'Russian GRU Sandworm group deploys new wiper variant AcidBurn targeting Ukrainian power distribution systems during winter heating season.', 'Sandworm deployed AcidBurn wiper malware against three Ukrainian regional power distribution companies. The malware targets both IT systems and OT/ICS components, specifically Schneider Electric SCADA platforms. Attack timed to coincide with sub-zero temperatures. Ukrainian CERT and international partners contained the attack before widespread outages occurred.', 'critical', 'malware', '{}', '{"Schneider Electric SCADA","Windows Server","Linux OT Systems","ICS/SCADA Networks"}', '{"Sandworm"}', '{"energy","government"}', 'Destructive Malware / ICS Targeting', 'CERT-UA / Mandiant', 'https://cert.gov.ua', '2026-03-16T07:00:00Z', '2026-03-17T12:00:00Z', '2026-03-15T00:00:00Z', '2026-03-15T00:00:00Z', NULL, true, '{"CERT-UA","Mandiant","CISA"}', '{"wiper","ukraine","ics","energy","sandworm","destructive"}', 'Ukraine'),

('Ivanti Connect Secure New Zero-Day Under Active Exploitation', 'ivanti-connect-secure-new-zero-day-2026', 'Another zero-day in Ivanti Connect Secure VPN appliances. Stack buffer overflow enables unauthenticated RCE. Third major Ivanti VPN zero-day in two years.', 'CVE-2026-18321 is a stack buffer overflow in Ivanti Connect Secure allowing unauthenticated RCE via crafted IKEv2 packets. Mandiant has observed exploitation by suspected Chinese state-sponsored actors. This is the third major zero-day in Ivanti VPN products since January 2024. Ivanti released emergency patches and recommends factory reset before patching.', 'critical', 'zero-day', '{"CVE-2026-18321"}', '{"Ivanti Connect Secure","Ivanti Policy Secure","Ivanti ZTA Gateways"}', '{}', '{"government","defense","technology","finance"}', 'Network / IKEv2 Protocol', 'Mandiant / Ivanti', 'https://www.ivanti.com/security', '2026-03-15T13:00:00Z', '2026-03-16T10:00:00Z', '2026-03-08T00:00:00Z', '2026-03-08T00:00:00Z', '2026-03-15T00:00:00Z', true, '{"CISA","Mandiant","Ivanti"}', '{"zero-day","vpn","ivanti","network-edge"}', 'Global'),

('APT28 Compromises European Defense Contractor via Outlook Zero-Day', 'apt28-european-defense-contractor-outlook', 'APT28 exploits Outlook NTLM relay zero-day to compromise a major European defense contractor. Classified project data at risk.', 'APT28 used CVE-2026-15899, an Outlook zero-day that triggers NTLM credential relay via a specially crafted calendar invite — no user interaction beyond receiving the email. Targeted a Tier-1 European defense contractor working on next-generation weapons systems. Access maintained for approximately three weeks before detection.', 'high', 'apt', '{"CVE-2026-15899"}', '{"Microsoft Outlook","Windows NTLM","Microsoft Exchange","Active Directory"}', '{"APT28"}', '{"defense","government","manufacturing"}', 'Email / NTLM Relay / Zero-Click', 'ANSSI / Microsoft Threat Intelligence', 'https://www.cert.ssi.gouv.fr', '2026-03-14T16:00:00Z', '2026-03-15T11:00:00Z', '2026-03-01T00:00:00Z', '2026-03-01T00:00:00Z', '2026-03-14T00:00:00Z', true, '{"ANSSI","Microsoft","NATO"}', '{"apt28","outlook","ntlm","defense","zero-click"}', 'Europe'),

('Rhysida Ransomware Attacks Five US Hospital Systems in Coordinated Campaign', 'rhysida-ransomware-five-us-hospitals', 'Rhysida ransomware group simultaneously attacks five US hospital systems, forcing ER diversions and surgical cancellations across 23 facilities.', 'Rhysida launched coordinated attacks against five US hospital systems spanning 23 facilities across eight states. All attacks initiated within a 4-hour window via compromised VPN credentials. EHR systems, lab systems, and medical imaging all encrypted. Multiple hospitals diverted emergency patients to neighboring facilities. FBI and HHS are providing incident response assistance.', 'critical', 'ransomware', '{}', '{"Epic EHR","Cerner","PACS Systems","Medical Imaging","VPN Appliances"}', '{"Rhysida"}', '{"healthcare"}', 'VPN Credential Compromise / Ransomware Deployment', 'HHS HC3 / FBI', 'https://www.hhs.gov/hc3', '2026-03-13T05:00:00Z', '2026-03-14T18:00:00Z', '2026-03-13T01:00:00Z', '2026-03-13T01:00:00Z', NULL, true, '{"HHS","FBI","CISA"}', '{"ransomware","healthcare","hospital","patient-safety","rhysida"}', 'United States'),

('Flax Typhoon IoT Botnet Resurfaces with 300,000 Compromised Devices', 'flax-typhoon-iot-botnet-300k-devices', 'Despite FBI disruption in 2024, Flax Typhoon has rebuilt its IoT botnet to over 300,000 compromised routers, cameras, and NAS devices worldwide.', 'Flax Typhoon rebuilt its botnet using vulnerabilities in SOHO routers, IP cameras, and NAS devices. The botnet serves as a proxy network for other Chinese intelligence operations, providing anonymization and relay capabilities. Lumen Black Lotus Labs identified the rebuilt infrastructure spanning 72 countries. FBI is coordinating with international partners for another disruption attempt.', 'high', 'malware', '{}', '{"SOHO Routers","IP Cameras","NAS Devices","IoT Devices"}', '{"Flax Typhoon"}', '{"telecommunications","government","technology"}', 'IoT Exploitation / Botnet', 'Lumen Black Lotus Labs / FBI', 'https://blog.lumen.com', '2026-03-12T14:00:00Z', '2026-03-13T09:00:00Z', '2026-02-15T00:00:00Z', '2026-02-15T00:00:00Z', NULL, true, '{"FBI","Lumen","CISA"}', '{"botnet","iot","china","proxy-network","flax-typhoon"}', 'Global'),

('Critical Cisco NX-OS Command Injection Affects Data Center Switches', 'cisco-nx-os-command-injection-data-center', 'Command injection in Cisco NX-OS CLI allows authenticated users to escalate to root on Nexus data center switches. PoC exploit published.', 'CVE-2026-20356 is a command injection in the NX-OS CLI that allows an authenticated user with basic access to execute arbitrary commands as root. A public PoC exploit was published within 48 hours of Cisco disclosure. Affects Nexus 3000, 5000, 7000, and 9000 series switches — the backbone of many enterprise data centers.', 'high', 'vulnerability', '{"CVE-2026-20356"}', '{"Cisco NX-OS","Nexus 3000","Nexus 5000","Nexus 7000","Nexus 9000"}', '{}', '{"technology","finance","telecommunications","government"}', 'Authenticated CLI / Command Injection', 'Cisco PSIRT', 'https://sec.cloudapps.cisco.com', '2026-03-11T10:00:00Z', '2026-03-12T08:00:00Z', '2026-03-04T00:00:00Z', NULL, '2026-03-11T00:00:00Z', true, '{"Cisco PSIRT","CISA"}', '{"cisco","nx-os","data-center","privilege-escalation","poc-available"}', 'Global'),

('Medusa Ransomware Campaign Targets 40+ US School Districts', 'medusa-ransomware-us-school-districts', 'Medusa ransomware group attacks over 40 US school districts via compromised RDP. Student and staff PII at risk. FBI issues sector-wide alert.', 'Medusa ransomware has compromised over 40 US school districts through exposed or credential-stuffed RDP endpoints. Stolen data includes student records with grades, disciplinary actions, IEPs, and staff SSNs. FBI and CISA have issued a joint advisory with specific IOCs and mitigation guidance for the K-12 sector.', 'high', 'ransomware', '{}', '{"Windows Server","RDP","Student Information Systems","Active Directory"}', '{"Medusa"}', '{"education","government"}', 'RDP Exploitation / Credential Stuffing', 'FBI / CISA Joint Advisory', 'https://www.cisa.gov', '2026-03-10T08:00:00Z', '2026-03-11T14:00:00Z', '2026-03-03T00:00:00Z', '2026-03-03T00:00:00Z', NULL, true, '{"FBI","CISA","MS-ISAC"}', '{"ransomware","education","k-12","student-data","medusa"}', 'United States');
